# pagerduty_escalation_policy.py — create or update the escalation policy via PagerDuty API
import requests

PD_TOKEN = "your-pagerduty-api-token"
HEADERS = {
    "Authorization": f"Token token={PD_TOKEN}",
    "Content-Type": "application/json",
    "Accept": "application/vnd.pagerduty+json;version=2",
}

def create_escalation_policy(
    name: str,
    tier1_schedule_id: str,
    tier2_schedule_id: str,
    tier3_user_id: str,
    tier4_user_id: str,
) -> dict:
    """Create a four-tier escalation policy for Claude incidents."""
    policy = {
        "escalation_policy": {
            "type": "escalation_policy",
            "name": name,
            "num_loops": 1,   # page cycle through all tiers once if no ack
            "on_call_handoff_notifications": "if_has_services",
            "escalation_rules": [
                {
                    # Tier 1: Primary on-call. Page immediately.
                    "escalation_delay_in_minutes": 5,   # T2 paged after 5 min no-ack
                    "targets": [
                        {"id": tier1_schedule_id, "type": "schedule_reference"}
                    ],
                },
                {
                    # Tier 2: Secondary on-call. Paged at T1+5 min.
                    "escalation_delay_in_minutes": 10,  # T3 paged after 10 more min
                    "targets": [
                        {"id": tier2_schedule_id, "type": "schedule_reference"}
                    ],
                },
                {
                    # Tier 3: Team lead. Paged at T1+15 min.
                    "escalation_delay_in_minutes": 15,  # T4 paged after 15 more min (P0 only)
                    "targets": [
                        {"id": tier3_user_id, "type": "user_reference"}
                    ],
                },
                {
                    # Tier 4: VP Eng. Only for P0 (service-level condition filters this).
                    "escalation_delay_in_minutes": 30,
                    "targets": [
                        {"id": tier4_user_id, "type": "user_reference"}
                    ],
                },
            ],
        }
    }
    resp = requests.post(
        "https://api.pagerduty.com/escalation_policies",
        headers=HEADERS,
        json=policy,
    )
    resp.raise_for_status()
    return resp.json()["escalation_policy"]

# Usage
policy = create_escalation_policy(
    name="Claude API Integration — Production",
    tier1_schedule_id="SPRIMARY",
    tier2_schedule_id="SSECONDARY",
    tier3_user_id="ULEAD",
    tier4_user_id="UVPENG",
)
print(f"Created policy: {policy['id']}")

# contact_audit.py — check when each escalation contact last verified their PD notification
from datetime import date, timedelta
import requests

PD_TOKEN = "your-pagerduty-api-token"
HEADERS = {"Authorization": f"Token token={PD_TOKEN}", "Accept": "application/vnd.pagerduty+json;version=2"}

def get_user_notification_rules(user_id: str) -> list[dict]:
    resp = requests.get(
        f"https://api.pagerduty.com/users/{user_id}/notification_rules",
        headers=HEADERS,
    )
    resp.raise_for_status()
    return resp.json()["notification_rules"]

def audit_escalation_contacts(user_ids: list[str]) -> list[dict]:
    """Return users with no phone/SMS notification rule configured."""
    issues = []
    for uid in user_ids:
        rules = get_user_notification_rules(uid)
        contact_types = {r["contact_method"]["type"] for r in rules}
        if "phone_contact_method" not in contact_types and "sms_contact_method" not in contact_types:
            issues.append({"user_id": uid, "issue": "no phone/SMS notification rule"})
    return issues

# Run before each quarter
issues = audit_escalation_contacts(["ULEAD", "UVPENG", "UPRIMARY", "USECONDARY"])
for issue in issues:
    print(f"ACTION REQUIRED: {issue['user_id']} — {issue['issue']}")
